     1→import { getErrorMessage } from "@/shared/types/api-error.types";
     2→import type { CreateNowPaymentsCheckoutRequest } from "@/shared/types/payment.types";
     3→import { toast } from "@/shared/ui/notification";
     4→import { useMutation, useQuery } from "@tanstack/react-query";
     5→import { nowPaymentsCheckoutService } from "../services/nowpayments-checkout.service";
     6→
     7→export function useCreateNowPaymentsCheckout() {
     8→  return useMutation({
     9→    mutationFn: (data: CreateNowPaymentsCheckoutRequest) =>
    10→      nowPaymentsCheckoutService.createCheckout(data),
    11→    onError: (error: unknown) => {
    12→      toast.error(
    13→        getErrorMessage(error, "Failed to create NOWPayments checkout"),
    14→      );
    15→    },
    16→  });
    17→}
    18→
    19→export function useNowPaymentsCurrencies() {
    20→  return useQuery({
    21→    queryKey: ["nowpayments", "currencies"],
    22→    queryFn: () => nowPaymentsCheckoutService.getCurrencies(),
    23→    staleTime: 5 * 60 * 1000, // 5 minutes
    24→  });
    25→}
