     1→import { getApi } from "@/shared/api/api";
     2→import { API_ROUTES } from "@/shared/config/api-routes";
     3→import type {
     4→  CreateNowPaymentsCheckoutRequest,
     5→  CreateNowPaymentsCheckoutResponse,
     6→  NowPaymentsCurrenciesResponse,
     7→} from "@/shared/types/payment.types";
     8→
     9→export const nowPaymentsCheckoutService = {
    10→  async createCheckout(
    11→    request: CreateNowPaymentsCheckoutRequest,
    12→  ): Promise<CreateNowPaymentsCheckoutResponse> {
    13→    const api = await getApi();
    14→    const { data } = await api.post<CreateNowPaymentsCheckoutResponse>(
    15→      API_ROUTES.NOWPAYMENTS_CHECKOUT,
    16→      request,
    17→    );
    18→    return data;
    19→  },
    20→
    21→  async getCurrencies(): Promise<NowPaymentsCurrenciesResponse> {
    22→    const api = await getApi();
    23→    const { data } = await api.get<NowPaymentsCurrenciesResponse>(
    24→      API_ROUTES.NOWPAYMENTS_CURRENCIES,
    25→    );
    26→    return data;
    27→  },
    28→};
