     1→"use client";
     2→
     3→import { useEffect, useState } from "react";
     4→import { QRCodeSVG } from "qrcode.react";
     5→import { Copy, Check, X } from "lucide-react";
     6→import { usePaymentPolling } from "@/shared/lib/hooks/use-payment-polling";
     7→import type { CreateNowPaymentsCheckoutResponse } from "@/shared/types/payment.types";
     8→import { Dialog, DialogContent, DialogTitle } from "@/shared/ui/dialog";
     9→import { toast } from "@/shared/ui/notification";
    10→
    11→interface NowPaymentsModalProps {
    12→  isOpen: boolean;
    13→  onClose: () => void;
    14→  checkoutSession: CreateNowPaymentsCheckoutResponse;
    15→  internalPaymentId: string;
    16→  onSuccess?: () => void;
    17→}
    18→
    19→export function NowPaymentsModal({
    20→  isOpen,
    21→  onClose,
    22→  checkoutSession,
    23→  internalPaymentId,
    24→  onSuccess,
    25→}: NowPaymentsModalProps) {
    26→  const [copied, setCopied] = useState(false);
    27→  const [confirmations, setConfirmations] = useState<number>(0);
    28→
    29→  const { payment } = usePaymentPolling(isOpen ? internalPaymentId : null, {
    30→    interval: 8000, // Increased from 3s to 8s to avoid rate limiting
    31→    maxInterval: 30_000, // Max 30 seconds with exponential backoff
    32→    enabled: isOpen,
    33→    onSuccess: () => {
    34→      toast.success("✅ Deposit successfully credited to your wallet!");
    35→      setTimeout(() => {
    36→        onSuccess?.();
    37→        onClose();
    38→      }, 2000);
    39→    },
    40→    onFailure: (failedPayment) => {
    41→      if (failedPayment.status === "EXPIRED") {
    42→        toast.error("⏰ Payment time expired. Please try again.");
    43→      } else {
    44→        toast.error("❌ Payment failed. Please contact support.");
    45→      }
    46→    },
    47→  });
    48→
    49→  useEffect(() => {
    50→    if (payment?.metadata?.confirmations) {
    51→      setConfirmations(payment.metadata.confirmations as number);
    52→    }
    53→  }, [payment]);
    54→
    55→  const handleCopy = async () => {
    56→    try {
    57→      await navigator.clipboard.writeText(checkoutSession.payAddress);
    58→      setCopied(true);
    59→      toast.success("Address copied to clipboard!");
    60→      setTimeout(() => setCopied(false), 2000);
    61→    } catch (_error) {
    62→      toast.error("Failed to copy address");
    63→    }
    64→  };
    65→
    66→  const getStatusInfo = () => {
    67→    if (!payment) {
    68→      return {
    69→        text: "🟡 Waiting for payment...",
    70→        color: "bg-yellow-50 text-yellow-700 border-yellow-200",
    71→      };
    72→    }
    73→
    74→    switch (payment.status) {
    75→      case "PENDING":
    76→        if (confirmations > 0) {
    77→          return {
    78→            text: `🟡 Confirming in blockchain (${confirmations} confirmations)...`,
    79→            color: "bg-yellow-50 text-yellow-700 border-yellow-200",
    80→          };
    81→        }
    82→        return {
    83→          text: "🟡 Payment received, waiting for blockchain confirmation...",
    84→          color: "bg-yellow-50 text-yellow-700 border-yellow-200",
    85→        };
    86→      case "SUCCEEDED":
    87→        return {
    88→          text: "🟢 Payment completed successfully!",
    89→          color: "bg-green-50 text-green-700 border-green-200",
    90→        };
    91→      case "FAILED":
    92→        return {
    93→          text: "🔴 Payment failed",
    94→          color: "bg-red-50 text-red-700 border-red-200",
    95→        };
    96→      case "EXPIRED":
    97→        return {
    98→          text: "🔴 Payment expired",
    99→          color: "bg-red-50 text-red-700 border-red-200",
   100→        };
   101→      default:
   102→        return {
   103→          text: "🟡 Waiting for payment...",
   104→          color: "bg-yellow-50 text-yellow-700 border-yellow-200",
   105→        };
   106→    }
   107→  };
   108→
   109→  const statusInfo = getStatusInfo();
   110→
   111→  return (
   112→    <Dialog open={isOpen} onOpenChange={onClose}>
   113→      <DialogContent className="max-h-[calc(100vh-2rem)] w-[calc(100%-2rem)] max-w-[92vw] overflow-y-auto p-0 sm:max-h-[calc(100vh-3rem)] sm:max-w-[520px]">
   114→        <div className="space-y-6 bg-card">
   115→          {/* Header */}
   116→          <div className="border-border border-b bg-gradient-to-r from-primary/10 via-card to-primary/10 px-4 py-4 sm:px-6 sm:py-5">
   117→            <div className="flex items-center justify-between">
   118→              <div>
   119→                <DialogTitle className="font-bold font-serif text-[22px] tracking-tight">
   120→                  Pay with Cryptocurrency
   121→                </DialogTitle>
   122→                <p className="mt-1 text-muted-foreground text-sm">
   123→                  Scan or copy the address to complete your deposit.
   124→                </p>
   125→              </div>
   126→              <button
   127→                type="button"
   128→                onClick={onClose}
   129→                className="rounded-full p-2 text-muted-foreground transition-colors hover:bg-primary/10 hover:text-foreground"
   130→              >
   131→                <X className="h-5 w-5" />
   132→              </button>
   133→            </div>
   134→          </div>
   135→
   136→          <div className="space-y-6 px-4 pb-6 sm:px-6">
   137→            {/* Status */}
   138→            <div
   139→              className={`flex items-center justify-center gap-2 rounded-full border px-4 py-2 text-center font-medium text-sm ${statusInfo.color}`}
   140→            >
   141→              <span className="h-2 w-2 rounded-full bg-current opacity-70" />
   142→              {statusInfo.text}
   143→            </div>
   144→
   145→            {/* QR Code */}
   146→            <div className="flex justify-center rounded-2xl border border-primary/15 bg-gradient-to-b from-card to-primary/5 p-5 shadow-sm sm:p-6">
   147→              <div className="rounded-xl bg-card p-3 shadow-[0_10px_30px_rgba(16,24,40,0.08)]">
   148→                <QRCodeSVG
   149→                  value={`${checkoutSession.payAddress}?amount=${checkoutSession.payAmount}`}
   150→                  size={256}
   151→                  level="H"
   152→                  includeMargin
   153→                  className="h-44 w-44 sm:h-56 sm:w-56"
   154→                />
   155→              </div>
   156→            </div>
   157→
   158→            {/* Payment Details */}
   159→            <div className="space-y-4">
   160→              {/* Address */}
   161→              <div className="rounded-xl border border-border bg-muted/30 p-4">
   162→                <div className="mb-2 text-muted-foreground text-xs uppercase tracking-wide">
   163→                  Payment Address
   164→                </div>
   165→                <div className="flex items-center gap-2">
   166→                  <code className="flex-1 overflow-x-auto font-mono text-foreground text-sm">
   167→                    {checkoutSession.payAddress}
   168→                  </code>
   169→                  <button
   170→                    type="button"
   171→                    onClick={handleCopy}
   172→                    className="rounded-lg border border-transparent p-2 text-muted-foreground transition-colors hover:border-border hover:bg-card"
   173→                    title="Copy address"
   174→                  >
   175→                    {copied ? (
   176→                      <Check className="h-5 w-5 text-primary" />
   177→                    ) : (
   178→                      <Copy className="h-5 w-5" />
   179→                    )}
   180→                  </button>
   181→                </div>
   182→              </div>
   183→
   184→              {/* Amount */}
   185→              <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
   186→                <div className="rounded-xl border border-border bg-card p-4 shadow-sm">
   187→                  <div className="mb-1 text-muted-foreground text-xs uppercase tracking-wide">
   188→                    Amount
   189→                  </div>
   190→                  <div className="font-bold font-serif text-foreground text-lg">
   191→                    {checkoutSession.payAmount} {checkoutSession.payCurrency}
   192→                  </div>
   193→                </div>
   194→
   195→                <div className="rounded-xl border border-border bg-card p-4 shadow-sm">
   196→                  <div className="mb-1 text-muted-foreground text-xs uppercase tracking-wide">
   197→                    Equivalent
   198→                  </div>
   199→                  <div className="font-bold font-serif text-foreground text-lg">
   200→                    ${checkoutSession.priceAmount} {checkoutSession.priceCurrency}
   201→                  </div>
   202→                </div>
   203→              </div>
   204→            </div>
   205→
   206→            {/* Instructions */}
   207→            <div className="space-y-2 rounded-xl border border-primary/15 bg-primary/5 p-4 text-foreground text-sm">
   208→              <p className="font-medium">Instructions</p>
   209→              <ol className="list-inside list-decimal space-y-1 text-foreground/80">
   210→                <li>Scan the QR code or copy the address</li>
   211→                <li>
   212→                  Send{" "}
   213→                  <strong>
   214→                    exactly {checkoutSession.payAmount}{" "}
   215→                    {checkoutSession.payCurrency}
   216→                  </strong>
   217→                </li>
   218→                <li>Wait for blockchain confirmation</li>
   219→                <li>Funds will be automatically credited to your wallet</li>
   220→              </ol>
   221→            </div>
   222→
   223→            {/* Warnings */}
   224→            <div className="space-y-2 text-muted-foreground text-xs">
   225→              <div className="flex items-center gap-2">
   226→                <span className="h-1.5 w-1.5 rounded-full bg-muted-foreground/70" />
   227→                Send exactly the specified amount
   228→              </div>
   229→              <div className="flex items-center gap-2">
   230→                <span className="h-1.5 w-1.5 rounded-full bg-muted-foreground/70" />
   231→                Use the correct network ({checkoutSession.payCurrency})
   232→              </div>
   233→              <div className="flex items-center gap-2">
   234→                <span className="h-1.5 w-1.5 rounded-full bg-muted-foreground/70" />
   235→                Do not close this window until confirmed
   236→              </div>
   237→            </div>
   238→          </div>
   239→        </div>
   240→      </DialogContent>
   241→    </Dialog>
   242→  );
   243→}
   244→

