     1→"use client";
     2→
     3→import { getCardIcon } from "@/shared/lib/utils/get-card-icon";
     4→import {
     5→  CRYPTO_NETWORK_LABELS,
     6→  type CryptoNetwork,
     7→} from "@/shared/types/payment.types";
     8→import type { WithdrawalRequestWithUser } from "@/shared/types/withdrawal-request.types";
     9→import {
    10→  WithdrawalMethodType,
    11→  WithdrawalRequestStatus,
    12→} from "@/shared/types/withdrawal-request.types";
    13→import { Badge } from "@/shared/ui/badge";
    14→import { PrimaryTable } from "@/shared/ui/table";
    15→import { format } from "date-fns";
    16→import { useMemo, type FC } from "react";
    17→import { CardOutline, LogoUsd } from "react-ionicons";
    18→import { formatDollarsToUSD } from "@/shared/lib/utils/price-formatter";
    19→import { resolveWithdrawalMethodType } from "./resolve-withdrawal-method-type";
    20→
    21→interface WithdrawalRequestsTableProps {
    22→  requests: WithdrawalRequestWithUser[];
    23→  onRowClick: (id: string) => void;
    24→}
    25→
    26→const STATUS_LABELS: Record<WithdrawalRequestStatus, string> = {
    27→  PENDING: "Pending",
    28→  APPROVED: "Approved",
    29→  REJECTED: "Rejected",
    30→  COMPLETED: "Completed",
    31→  CANCELLED: "Cancelled",
    32→};
    33→
    34→const STATUS_VARIANTS: Record<
    35→  WithdrawalRequestStatus,
    36→  "default" | "primary" | "success" | "error" | "warning"
    37→> = {
    38→  PENDING: "warning",
    39→  APPROVED: "primary",
    40→  REJECTED: "error",
    41→  COMPLETED: "success",
    42→  CANCELLED: "default",
    43→};
    44→
    45→export const WithdrawalRequestsTable: FC<WithdrawalRequestsTableProps> = ({
    46→  requests,
    47→  onRowClick,
    48→}) => {
    49→  const columns = useMemo(
    50→    () => [
    51→      {
    52→        key: "user",
    53→        header: "User",
    54→        align: "left" as const,
    55→        minWidth: 150,
    56→        maxWidth: 200,
    57→        render: (_value: unknown, row: Record<string, unknown>) => {
    58→          const request = row as unknown as WithdrawalRequestWithUser;
    59→
    60→          return (
    61→            <div className="overflow-hidden">
    62→              <span
    63→                className="block overflow-hidden text-ellipsis whitespace-nowrap"
    64→                title={request.user.fullName}
    65→              >
    66→                {request.user.fullName}
    67→              </span>
    68→            </div>
    69→          );
    70→        },
    71→      },
    72→      {
    73→        key: "email",
    74→        header: "Email",
    75→        align: "left" as const,
    76→        minWidth: 150,
    77→        maxWidth: 250,
    78→        render: (_value: unknown, row: Record<string, unknown>) => {
    79→          const request = row as unknown as WithdrawalRequestWithUser;
    80→
    81→          return (
    82→            <div className="overflow-hidden">
    83→              <span
    84→                className="block overflow-hidden text-ellipsis whitespace-nowrap"
    85→                title={request.user.email}
    86→              >
    87→                {request.user.email}
    88→              </span>
    89→            </div>
    90→          );
    91→        },
    92→      },
    93→      {
    94→        key: "amount",
    95→        header: "Amount",
    96→        align: "left" as const,
    97→        width: 100,
    98→        className: "font-bold",
    99→        render: (_value: unknown, row: Record<string, unknown>) => {
   100→          const request = row as unknown as WithdrawalRequestWithUser;
   101→
   102→          return formatDollarsToUSD(request.amount);
   103→        },
   104→      },
   105→      {
   106→        key: "method",
   107→        header: "Method",
   108→        align: "left" as const,
   109→        minWidth: 180,
   110→        render: (_value: unknown, row: Record<string, unknown>) => {
   111→          const request = row as unknown as WithdrawalRequestWithUser;
   112→          const methodType = resolveWithdrawalMethodType(request);
   113→          const isCrypto =
   114→            methodType === WithdrawalMethodType.CRYPTO;
   115→          const isPayPal = methodType === WithdrawalMethodType.PAYPAL;
   116→          const isNowPayments =
   117→            methodType === WithdrawalMethodType.NOWPAYMENTS;
   118→          let paypalTypeLabel = "PayPal";
   119→          if (request.paypalMethod?.type === "PAYPAL_ACCOUNT") {
   120→            paypalTypeLabel = "PayPal Account";
   121→          } else if (request.paypalMethod?.type === "PAYPAL_BANK") {
   122→            paypalTypeLabel = "PayPal Bank";
   123→          }
   124→
   125→          let stripeDisplayName = "Card withdrawal";
   126→          if (methodType === WithdrawalMethodType.BANK) {
   127→            stripeDisplayName = "Bank withdrawal";
   128→          }
   129→          if (request.stripeMethod) {
   130→            stripeDisplayName =
   131→              request.stripeMethod.nickname ||
   132→              `${request.stripeMethod.type === "CARD" ? request.stripeMethod.brand?.toUpperCase() || "Card" : "Bank"} ••${request.stripeMethod.last4}`;
   133→          }
   134→
   135→          if (isCrypto && request.cryptoPaymentMethod) {
   136→            const networkDisplay = (request.cryptoPaymentMethod
   137→              .network as CryptoNetwork)
   138→              ? CRYPTO_NETWORK_LABELS[
   139→                  request.cryptoPaymentMethod.network as CryptoNetwork
   140→                ]
   141→              : undefined;
   142→
   143→            return (
   144→              <div className="flex items-center gap-2">
   145→                <div className="flex h-8 w-10 shrink-0 items-center justify-center rounded-[6px] border border-input bg-gradient-to-br from-primary/5 to-primary/10">
   146→                  <LogoUsd
   147→                    width="16px"
   148→                    height="16px"
   149→                    className="text-primary"
   150→                  />
   151→                </div>
   152→                <div className="flex min-w-0 flex-col">
   153→                  <span className="truncate font-serif text-[#212529] text-xs leading-tight">
   154→                    {request.cryptoPaymentMethod.label}
   155→                  </span>
   156→                  <div className="flex items-center gap-1">
   157→                    <Badge
   158→                      variant="outline"
   159→                      className="h-fit px-1 py-0 text-[9px]"
   160→                    >
   161→                      {networkDisplay}
   162→                    </Badge>
   163→                    <span className="font-mono text-[9px] text-muted-foreground leading-tight">
   164→                      {request.cryptoPaymentMethod.address.slice(0, 6)}...
   165→                      {request.cryptoPaymentMethod.address.slice(-4)}
   166→                    </span>
   167→                  </div>
   168→                </div>
   169→              </div>
   170→            );
   171→          }
   172→
   173→          if (isPayPal) {
   174→            return (
   175→              <div className="flex items-center gap-2">
   176→                <div className="flex h-8 w-10 shrink-0 items-center justify-center rounded-[6px] border border-input bg-white">
   177→                  <span className="font-bold font-serif text-primary text-xs">
   178→                    PayPal
   179→                  </span>
   180→                </div>
   181→                <div className="flex min-w-0 flex-col">
   182→                  <span className="truncate font-serif text-[#212529] text-xs leading-tight">
   183→                    {request.paypalMethod?.nickname ||
   184→                      request.paypalMethod?.email ||
   185→                      "PayPal withdrawal"}
   186→                  </span>
   187→                  <span className="font-serif text-[10px] text-muted-foreground leading-tight">
   188→                    {paypalTypeLabel}
   189→                  </span>
   190→                </div>
   191→              </div>
   192→            );
   193→          }
   194→
   195→          if (isNowPayments) {
   196→            return (
   197→              <div className="flex items-center gap-2">
   198→                <div className="flex h-8 w-10 shrink-0 items-center justify-center rounded-[6px] border border-input bg-white">
   199→                  <span className="font-bold font-serif text-primary text-xs">
   200→                    NP
   201→                  </span>
   202→                </div>
   203→                <div className="flex min-w-0 flex-col">
   204→                  <span className="truncate font-serif text-[#212529] text-xs leading-tight">
   205→                    NowPayments
   206→                  </span>
   207→                  <span className="font-serif text-[10px] text-muted-foreground leading-tight">
   208→                    Crypto Payment
   209→                  </span>
   210→                </div>
   211→              </div>
   212→            );
   213→          }
   214→
   215→          if (
   216→            request.stripeMethod ||
   217→            methodType === WithdrawalMethodType.CARD ||
   218→            methodType === WithdrawalMethodType.BANK
   219→          ) {
   220→            const cardIcon =
   221→              request.stripeMethod?.type === "CARD"
   222→                ? getCardIcon(request.stripeMethod.brand)
   223→                : null;
   224→
   225→            return (
   226→              <div className="flex items-center gap-2">
   227→                <div className="flex h-8 w-10 shrink-0 items-center justify-center rounded-[6px] border border-input bg-white">
   228→                  {cardIcon || (
   229→                    <CardOutline
   230→                      width="16px"
   231→                      height="16px"
   232→                      className="text-muted-foreground"
   233→                    />
   234→                  )}
   235→                </div>
   236→                <div className="flex min-w-0 flex-col">
   237→                  <span className="truncate font-serif text-[#212529] text-xs leading-tight">
   238→                    {stripeDisplayName}
   239→                  </span>
   240→                  <span className="font-serif text-[10px] text-muted-foreground leading-tight">
   241→                    {methodType === WithdrawalMethodType.BANK
   242→                      ? "BANK"
   243→                      : "CARD"}
   244→                  </span>
   245→                </div>
   246→              </div>
   247→            );
   248→          }
   249→
   250→          return (
   251→            <span className="font-serif text-muted-foreground text-xs">
   252→              No method
   253→            </span>
   254→          );
   255→        },
   256→      },
   257→      {
   258→        key: "status",
   259→        header: "Status",
   260→        align: "center" as const,
   261→        width: 120,
   262→        render: (_value: unknown, row: Record<string, unknown>) => {
   263→          const request = row as unknown as WithdrawalRequestWithUser;
   264→
   265→          return (
   266→            <div className="flex justify-center">
   267→              <Badge variant={STATUS_VARIANTS[request.status]}>
   268→                {STATUS_LABELS[request.status]}
